CREATE TRIGGER [dbo].[OrderItemAttribute_History]ON [dbo].[OrderItemAttribute]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.OrderItemAttributeId IS NOT NULL AND d.OrderItemAttributeId IS NULL THEN 'I' 		WHEN i.OrderItemAttributeId IS NOT NULL AND d.OrderItemAttributeId IS NOT NULL THEN 'U' 		WHEN i.OrderItemAttributeId IS NULL AND d.OrderItemAttributeId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.OrderItemAttributeId = d.OrderItemAttributeId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.dbo_OrderItemAttribute([OrderItemAttributeId], [OrderItemId], [ItemAttributeTypeId], [AttributeValue], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [OrderItemAttributeId], [OrderItemId], [ItemAttributeTypeId], [AttributeValue], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.dbo_OrderItemAttribute([OrderItemAttributeId], [OrderItemId], [ItemAttributeTypeId], [AttributeValue], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [OrderItemAttributeId], [OrderItemId], [ItemAttributeTypeId], [AttributeValue], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND